    ToMod();
  }

  ModInt operator+(const ModInt& other) const {
    return ModInt(value + other.value);
  }

  ModInt operator*(const ModInt& other) const {
    return ModInt(value * other.value);
  }

  ModInt operator-(const ModInt& other) const {
    return ModInt(value - other.value);
  }

  void ToMod() {
    value %= cMod;
    if (value < 0) {
      value += cMod;
    }
  }
};

ostream& operator<<(ostream& out, ModInt value) {
  out << value.value;
  return out;
}

void Solve() {
  int n;
  cin >> n;
  string s;
  cin >> s;
  vector<int> pot(n, 0);
  for (int i = 0; i < n; ++i) {
    if (i != 0) {
      pot[i] = pot[i - 1];
